# Prepare the Host Name (Only the chosen name, max 15 chars) $CleanHostName = $RandomSelection -replace '[^a-zA-Z0-9\-]', '' $FinalHostName = $CleanHostName.Substring(0, [math]::Min(15, $CleanHostName.Length))
